    41→// ExponentialBlockRanges returns the time ranges based on the stepSize.
    42→func ExponentialBlockRanges(minSize int64, steps, stepSize int) []int64 {
    43→	ranges := make([]int64, 0, steps)
    44→	curRange := minSize
    45→	for i := 0; i < steps; i++ {
    46→		ranges = append(ranges, curRange)
    47→		curRange *= int64(stepSize)
    48→	}
    49→
    50→	return ranges
    51→}
    52→
    53→// Compactor provides compaction against an underlying storage
    54→// of time series data.
    55→type Compactor interface {
    56→	// Plan returns a set of directories that can be compacted concurrently.
    57→	// The directories can be overlapping.
    58→	// Results returned when compactions are in progress are undefined.
    59→	Plan(dir string) ([]string, error)
    60→
    61→	// Write persists a Block into a directory.
    62→	// No Block is written when resulting Block has 0 samples, and returns empty ulid.ULID{}.
    63→	Write(dest string, b BlockReader, mint, maxt int64, base *BlockMeta) (ulid.ULID, error)
    64→
    65→	// Compact runs compaction against the provided directories. Must
    66→	// only be called concurrently with results of Plan().
    67→	// Can optionally pass a list of already open blocks,
    68→	// to avoid having to reopen them.
    69→	// When resulting Block has 0 samples
    70→	//  * No block is written.
    71→	//  * The source dirs are marked Deletable.
    72→	//  * Returns empty ulid.ULID{}.
    73→	Compact(dest string, dirs []string, open []*Block) (ulid.ULID, error)
    74→}
    75→
    76→// LeveledCompactor implements the Compactor interface.
    77→type LeveledCompactor struct {
    78→	metrics                     *CompactorMetrics
    79→	logger                      log.Logger
    80→	ranges                      []int64
    81→	chunkPool                   chunkenc.Pool
    82→	ctx                         context.Context
    83→	maxBlockChunkSegmentSize    int64
    84→	mergeFunc                   storage.VerticalChunkSeriesMergeFunc
    85→	postingsEncoder             index.PostingsEncoder
    86→	enableOverlappingCompaction bool
    87→}
    88→
    89→type CompactorMetrics struct {
    90→	Ran               prometheus.Counter
    91→	PopulatingBlocks  prometheus.Gauge
    92→	OverlappingBlocks prometheus.Counter
    93→	Duration          prometheus.Histogram
    94→	ChunkSize         prometheus.Histogram
    95→	ChunkSamples      prometheus.Histogram
    96→	ChunkRange        prometheus.Histogram
    97→}
    98→
    99→// NewCompactorMetrics initializes metrics for Compactor.
   100→func NewCompactorMetrics(r prometheus.Registerer) *CompactorMetrics {
   101→	m := &CompactorMetrics{}
   102→
   103→	m.Ran = prometheus.NewCounter(prometheus.CounterOpts{
   104→		Name: "prometheus_tsdb_compactions_total",
   105→		Help: "Total number of compactions that were executed for the partition.",
   106→	})
   107→	m.PopulatingBlocks = prometheus.NewGauge(prometheus.GaugeOpts{
   108→		Name: "prometheus_tsdb_compaction_populating_block",
   109→		Help: "Set to 1 when a block is currently being written to the disk.",
   110→	})
   111→	m.OverlappingBlocks = prometheus.NewCounter(prometheus.CounterOpts{
   112→		Name: "prometheus_tsdb_vertical_compactions_total",
   113→		Help: "Total number of compactions done on overlapping blocks.",
   114→	})
   115→	m.Duration = prometheus.NewHistogram(prometheus.HistogramOpts{
   116→		Name:                            "prometheus_tsdb_compaction_duration_seconds",
   117→		Help:                            "Duration of compaction runs",
   118→		Buckets:                         prometheus.ExponentialBuckets(1, 2, 14),
   119→		NativeHistogramBucketFactor:     1.1,
   120→		NativeHistogramMaxBucketNumber:  100,
   121→		NativeHistogramMinResetDuration: 1 * time.Hour,
   122→	})
   123→	m.ChunkSize = prometheus.NewHistogram(prometheus.HistogramOpts{
   124→		Name:    "prometheus_tsdb_compaction_chunk_size_bytes",
   125→		Help:    "Final size of chunks on their first compaction",
   126→		Buckets: prometheus.ExponentialBuckets(32, 1.5, 12),
   127→	})
   128→	m.ChunkSamples = prometheus.NewHistogram(prometheus.HistogramOpts{
   129→		Name:    "prometheus_tsdb_compaction_chunk_samples",
   130→		Help:    "Final number of samples on their first compaction",
   131→		Buckets: prometheus.ExponentialBuckets(4, 1.5, 12),
   132→	})
   133→	m.ChunkRange = prometheus.NewHistogram(prometheus.HistogramOpts{
   134→		Name:    "prometheus_tsdb_compaction_chunk_range_seconds",
   135→		Help:    "Final time range of chunks on their first compaction",
   136→		Buckets: prometheus.ExponentialBuckets(100, 4, 10),
   137→	})
   138→
   139→	if r != nil {
   140→		r.MustRegister(
   141→			m.Ran,
   142→			m.PopulatingBlocks,
   143→			m.OverlappingBlocks,
   144→			m.Duration,
   145→			m.ChunkRange,
   146→			m.ChunkSamples,
   147→			m.ChunkSize,
   148→		)
   149→	}
   150→	return m
   151→}
