   606→// write creates a new block that is the union of the provided blocks into dir.
   607→func (c *LeveledCompactor) write(dest string, meta *BlockMeta, blockPopulator BlockPopulator, blocks ...BlockReader) (err error) {
   608→	dir := filepath.Join(dest, meta.ULID.String())
   609→	tmp := dir + tmpForCreationBlockDirSuffix
   610→	var closers []io.Closer
   611→	defer func(t time.Time) {
   612→		err = tsdb_errors.NewMulti(err, tsdb_errors.CloseAll(closers)).Err()
   613→
   614→		// RemoveAll returns no error when tmp doesn't exist so it is safe to always run it.
   615→		if err := os.RemoveAll(tmp); err != nil {
   616→			level.Error(c.logger).Log("msg", "removed tmp folder after failed compaction", "err", err.Error())
   617→		}
   618→		c.metrics.Ran.Inc()
   619→		c.metrics.Duration.Observe(time.Since(t).Seconds())
   620→	}(time.Now())
   621→
   622→	if err = os.RemoveAll(tmp); err != nil {
   623→		return err
   624→	}
   625→
   626→	if err = os.MkdirAll(tmp, 0o777); err != nil {
   627→		return err
   628→	}
   629→
   630→	// Populate chunk and index files into temporary directory with
   631→	// data of all blocks.
   632→	var chunkw ChunkWriter
   633→
   634→	chunkw, err = chunks.NewWriterWithSegSize(chunkDir(tmp), c.maxBlockChunkSegmentSize)
   635→	if err != nil {
   636→		return fmt.Errorf("open chunk writer: %w", err)
   637→	}
   638→	closers = append(closers, chunkw)
   639→	// Record written chunk sizes on level 1 compactions.
   640→	if meta.Compaction.Level == 1 {
   641→		chunkw = &instrumentedChunkWriter{
   642→			ChunkWriter: chunkw,
   643→			size:        c.metrics.ChunkSize,
   644→			samples:     c.metrics.ChunkSamples,
   645→			trange:      c.metrics.ChunkRange,
   646→		}
   647→	}
   648→
   649→	indexw, err := index.NewWriterWithEncoder(c.ctx, filepath.Join(tmp, indexFilename), c.postingsEncoder)
   650→	if err != nil {
   651→		return fmt.Errorf("open index writer: %w", err)
   652→	}
   653→	closers = append(closers, indexw)
   654→
   655→	if err := blockPopulator.PopulateBlock(c.ctx, c.metrics, c.logger, c.chunkPool, c.mergeFunc, blocks, meta, indexw, chunkw); err != nil {
   656→		return fmt.Errorf("populate block: %w", err)
   657→	}
   658→
   659→	select {
   660→	case <-c.ctx.Done():
   661→		return c.ctx.Err()
   662→	default:
   663→	}
   664→
   665→	// We are explicitly closing them here to check for error even
   666→	// though these are covered under defer. This is because in Windows,
   667→	// you cannot delete these unless they are closed and the defer is to
   668→	// make sure they are closed if the function exits due to an error above.
   669→	errs := tsdb_errors.NewMulti()
   670→	for _, w := range closers {
   671→		errs.Add(w.Close())
   672→	}
   673→	closers = closers[:0] // Avoid closing the writers twice in the defer.
   674→	if errs.Err() != nil {
   675→		return errs.Err()
   676→	}
   677→
   678→	// Populated block is empty, so exit early.
   679→	if meta.Stats.NumSamples == 0 {
   680→		return nil
   681→	}
   682→
   683→	if _, err = writeMetaFile(c.logger, tmp, meta); err != nil {
   684→		return fmt.Errorf("write merged meta: %w", err)
   685→	}
   686→
   687→	// Create an empty tombstones file.
   688→	if _, err := tombstones.WriteFile(c.logger, tmp, tombstones.NewMemTombstones()); err != nil {
   689→		return fmt.Errorf("write new tombstones file: %w", err)
   690→	}
   691→
   692→	df, err := fileutil.OpenDir(tmp)
   693→	if err != nil {
   694→		return fmt.Errorf("open temporary block dir: %w", err)
   695→	}
   696→	defer func() {
   697→		if df != nil {
   698→			df.Close()
   699→		}
   700→	}()
   701→
   702→	if err := df.Sync(); err != nil {
   703→		return fmt.Errorf("sync temporary dir file: %w", err)
   704→	}
   705→
   706→	// Close temp dir before rename block dir (for windows platform).
   707→	if err = df.Close(); err != nil {
   708→		return fmt.Errorf("close temporary dir: %w", err)
   709→	}
   710→	df = nil
   711→
   712→	// Block successfully written, make it visible in destination dir by moving it from tmp one.
   713→	if err := fileutil.Replace(tmp, dir); err != nil {
   714→		return fmt.Errorf("rename block dir: %w", err)
   715→	}
   716→
   717→	return nil
   718→}
